		var err error
		progress, err = usecase.progressRepository.getProgress(gctx, params.userId, params.courseId)
		return err
	})
	if err := g.Wait(); err != nil {
		return "", err
	}

	if err := course.checkEnrollable(params.userId); err != nil {
		return "", err
	}

	if params.sectionNumber == nil && params.topicNumber != nil {
		return "", ErrTopicNumberRequireSectionNumber
	}

	section, topic, err := course.resolveTopic(params.sectionNumber, params.topicNumber, progress.lastTopicPosition())
	if err != nil {
		return "", err
	}

	topicId := progress.start(section.sectionId, topic.topicId, section.number, topic.number)

	return topicId, usecase.progressRepository.save(ctx, &progress)
}

